import axios from 'axios'
import React, { useEffect, useState } from 'react'

export default function ViewEmployee() {

  const [employees, setEmployees] = useState([])
  const [showform, setshowform] = useState(false)

  let [profile, setProfile] = useState("");
  let [firstname, setfirstname] = useState("");
  let [lastname, setlastname] = useState("");
  let [middlename, setmiddlename] = useState("");
  let [email, setemail] = useState("");
  let [contactno, setcontactno] = useState("");
  let [gender, setgender] = useState("");
  let [dob ,setdob] = useState("");
  let [caddress, setcaddress] = useState("");
  let [paddress, setpaddress] = useState("");
  let [adharno ,setadharno] = useState("");
  let [edu, setedu] = useState("");
  let [panno, setpanno] = useState("");
  let [exp, setexp] = useState("");
  let [salary, setsalary] = useState("");
  let [designation, setdesignation] = useState("");
  let [department, setdepartment] = useState("");
  let [reportingmanager, setreportingmanager] = useState("");
  let [worklocation ,setworklocation] = useState("");
  let [status, setstatus] = useState("");
  let [joiningdate, setjoiningdate] = useState("");

  let [empid,setempid] = useState("");

  // search
  let [searchby, setsearchby]=useState("");
  let [keyword, setkeyword]=useState("");
  let [searchResult, setsearchResult]=useState([]);

  // load data
  useEffect(()=>{
    loadEmployees();
  },[])

  const loadEmployees = () =>{
    axios.get("http://localhost:8080/findallemp")
      .then((response)=>{
        setEmployees(response.data);
      })
      .catch(()=>{
        alert("Error in fetching data")
      })
  }

  // delete
  const deleteEmployee = (id)=>{
    axios.delete(`http://localhost:8080/deleteemp/${id}`)
    .then((response)=>{
        alert(response.data);

        // remove from UI
        setEmployees(employees.filter(emp => emp.id !== id))
    })
    .catch(()=>{
        alert("Error deleting employee")
    })
  }

  // ready to update
  let readytoupdate=(emp)=>{
    setshowform(true);

    setfirstname(emp.firstname);
    setmiddlename(emp.middlename)
    setlastname(emp.lastname)
    setemail(emp.email)
    setcontactno(emp.contactno)
    setgender(emp.gender)
    setdob(emp.dob)
    setcaddress(emp.caddress)
    setpaddress(emp.paddress)
    setadharno(emp.adharno)
    setpanno(emp.panno)
    setexp(emp.exp)
    setsalary(emp.salary)
    setedu(emp.edu)
    setdesignation(emp.designation)
    setdepartment(emp.department)
    setworklocation(emp.worklocation)
    setreportingmanager(emp.reportingmanager)
    setstatus(emp.status)
    setjoiningdate(emp.joiningdate)
    setProfile(emp.profile)

    setempid(emp.id)   // ✅ FIXED
  }

  // update
  let updateemployee=(e)=>{
    e.preventDefault();

    let newemp = {
      firstname,lastname,middlename,dob,gender,caddress,paddress,adharno,
      panno,profile,email,contactno,designation,department,salary,
      reportingmanager,exp,worklocation,status,joiningdate,edu
    }

    axios.put(`http://localhost:8080/updateemp?empid=${empid}`, newemp)
    .then((response)=>{
        alert(response.data);
        setshowform(false);
        loadEmployees();   // reload updated data
    })
    .catch(()=>{
         alert("Error in updating employee")
    })
  }

  // search
  let searchemployee=()=>{
    let url;

    if(searchby=="firstname"){
        url=`http://localhost:8080/findbyfirstname?firstname=${keyword}`
    }
    else if(searchby=="lastname"){
        url=`http://localhost:8080/findbylastname?lastname=${keyword}`
    }
    else if(searchby=="department"){
        url=`http://localhost:8080/findbydept?department=${keyword}`
    }
    else if(searchby=="designation"){
        url=`http://localhost:8080/findbydesig?designation=${keyword}`
    }
    else if(searchby=="empid"){
        url=`http://localhost:8080/findbyempid?empid=${keyword}`
    }
    else{
        alert("Select valid search option");
        return;
    }

    axios.get(url)
    .then((response)=>{
        setsearchResult(response.data);
    })
    .catch(()=>{
        alert("Error in searching")
    })
  }

  return (
    <div className='maindiv'>

      <br/>

      {/* Search */}
      <div>
        Select searchby :
        <select onChange={(e)=>setsearchby(e.target.value)}>
          <option>Search Employee</option>
          <option value="firstname">By FirstName</option>
          <option value="lastname">By LastName</option>
          <option value="department">By Department</option>
          <option value="designation">By Designation</option>
          <option value="empid">By ID</option>
        </select>

        {searchby &&
          <div>
            <input type='text'
              placeholder={`Enter ${searchby}`}
              onChange={(e)=>setkeyword(e.target.value)}
            />
            <button onClick={searchemployee}>Search</button>
          </div>
        }
      </div>

      <br/>

      <div className="container-fluid">
        <div className="row">

        {(searchResult.length>0?searchResult:employees).map((emp)=>(
          <div className="col-md-4 mb-2" key={emp.id}>

            <div className="card" style={{width:"18rem"}}>

              <img src={emp.profile || null} className="card-img-top" alt="profile"/>

              <div className="card-body">

                <h5>
                  {emp.firstname} {emp.middlename} {emp.lastname}
                </h5>

                <p><strong>Contact:</strong> {emp.contactno}</p>
                <p><strong>Email:</strong> {emp.email}</p>
                <p><strong>Department:</strong> {emp.department}</p>
                <p><strong>Designation:</strong> {emp.designation}</p>

                <button className="btn btn-warning me-2"
                  onClick={()=> deleteEmployee(emp.id)}>
                  Delete
                </button>

                <button className="btn btn-danger"
                  onClick={()=> readytoupdate(emp)}>
                  Update
                </button>

              </div>
            </div>
          </div>
        ))}

        </div>
      </div>

      {/* Update Form */}
      {showform &&
      <div className="modal d-block">
        <div className="modal-dialog">
          <div className="modal-content">

            <div className="modal-header">
              <h5>Update Employee</h5>
              <button onClick={()=>setshowform(false)}>X</button>
            </div>

            <div className="modal-body">
              <form onSubmit={updateemployee}>

                <input value={firstname} onChange={(e)=>setfirstname(e.target.value)} placeholder="First Name"/>
                <input value={lastname} onChange={(e)=>setlastname(e.target.value)} placeholder="Last Name"/>

                <button className="btn btn-primary mt-3">Update</button>

              </form>
            </div>

          </div>
        </div>
      </div>
      }

    </div>
  )
}
